SELECT
    p.id as id,
    p.slug as slug,
    p.title as title,
    p.page_type as pageType,
    p.published as published,
    p.published_at as publishedAt
FROM cms_pages p

    AND p.id = #{id}
    AND p.slug LIKE CONCAT('%', #{slug}, '%')
    AND p.title LIKE CONCAT('%', #{title}, '%')
    AND p.page_type = #{pageType}
    AND p.published = #{published}
    AND p.published_at >= #{startDate}
    AND p.published_at <= #{endDate}

${orderby} ${pagination}

SELECT count(*)
FROM cms_pages p

    AND p.id = #{id}
    AND p.slug LIKE CONCAT('%', #{slug}, '%')
    AND p.title LIKE CONCAT('%', #{title}, '%')
    AND p.page_type = #{pageType}
    AND p.published = #{published}
    AND p.published_at >= #{startDate}
    AND p.published_at <= #{endDate}

