SELECT m.id as id, m.file_key as fileKey, m.original_name as originalName, m.cdn_url as cdnUrl, m.mime_type as mimeType, m.file_size_bytes as fileSizeBytes, m.width as width, m.height as height, m.alt_text as altText, m.folder as folder FROM cms_media m
AND m.id = #{id} AND m.original_name LIKE CONCAT('%', #{originalName}, '%') AND m.mime_type = #{mimeType} AND m.folder = #{folder}
${orderby} ${pagination}

SELECT count(*)
FROM cms_media m

    AND m.id = #{id}
    AND m.original_name LIKE CONCAT('%', #{originalName}, '%')
    AND m.mime_type = #{mimeType}
    AND m.folder = #{folder}

