    a.status as status,
    a.dismissible as dismissible,
    a.scheduled_date as scheduledDate,
    a.expiry_date as expiryDate,
    a.created_time as createdAt
FROM announcement a

    AND a.id = #{id}
    AND a.title LIKE CONCAT('%', #{title}, '%')
    AND a.announcement_type = #{announcementType}
    AND a.target_audience = #{targetAudience}
    AND a.priority = #{priority}
